// // This module generates a partial product bit (PPBIT) for a multiplication operation using Booth encoding. It takes into account the encoded multiplier bits and their neighboring conditions to determine the partial product bit.
module PP_LOW ( ONEPOS, ONENEG, TWONEG, INA, INB, PPBIT );
input  ONEPOS;
input  ONENEG;
input  TWONEG;
input  INA;
input  INB;
output PPBIT;
   assign PPBIT = (ONEPOS & INA) | (ONENEG & INB) | TWONEG;
endmodule
